TEST(CryptographyCipherFunctions, chacha20poly1305_roundripTest)
{
	const std::string plaintextStr = "This is the plaintext";

	Cryptography::CipherKey cipherKey;
	vectorToArray(hexToBytes("0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b"), cipherKey.raw);

	Cryptography::Nonce nonce = 0x1234567890ABCDEF;

	const Cryptography::DynByteSequence associatedData = Cryptography::DynByteSequence::fromVector(hexToBytes("BBBBBBBB"));

	const Cryptography::DynByteSequence plaintext = Cryptography::DynByteSequence::fromVector(strToBytes(plaintextStr));

	Cryptography::DynByteSequence ciphertext;
	ciphertext.clearResize(plaintext.size() + Cryptography::CipherAuthDataSize);
	ASSERT_EQ(Cryptography::encrypt_chacha20poly1305(cipherKey, nonce, associatedData, plaintext, ciphertext), Cryptography::EncryptResult::Success);

	Cryptography::DynByteSequence resultPlaintext;
	resultPlaintext.clearResize(plaintext.size());
	ASSERT_EQ(Cryptography::decrypt_chacha20poly1305(cipherKey, nonce, associatedData, ciphertext, resultPlaintext), Cryptography::DecryptResult::Success);

	EXPECT_EQ(resultPlaintext.raw, strToBytes(plaintextStr));
}

TEST(CryptographyCipherFunctions, chacha20poly1305_roundripRandomTest)
{
	const std::string plaintextStr = "This is the plaintext";

	Cryptography::CipherKey cipherKey;
	Cryptography::fillWithRandomBytes(cipherKey.raw);

	Cryptography::Nonce nonce;
	Cryptography::fillWithRandomBytes(std::span(reinterpret_cast<std::byte*>(&nonce), sizeof(nonce)));

	std::vector<std::byte> associatedDataRaw;
	associatedDataRaw.resize(20);
	Cryptography::fillWithRandomBytes(associatedDataRaw);
	const Cryptography::DynByteSequence associatedData = Cryptography::DynByteSequence::fromVector(std::move(associatedDataRaw));

	const Cryptography::DynByteSequence plaintext = Cryptography::DynByteSequence::fromVector(strToBytes(plaintextStr));

	Cryptography::DynByteSequence ciphertext;
	ciphertext.clearResize(plaintext.size() + Cryptography::CipherAuthDataSize);
	ASSERT_EQ(Cryptography::encrypt_chacha20poly1305(cipherKey, nonce, associatedData, plaintext, ciphertext), Cryptography::EncryptResult::Success);

	Cryptography::DynByteSequence resultPlaintext;
	resultPlaintext.clearResize(plaintext.size());
	ASSERT_EQ(Cryptography::decrypt_chacha20poly1305(cipherKey, nonce, associatedData, ciphertext, resultPlaintext), Cryptography::DecryptResult::Success);

	EXPECT_EQ(resultPlaintext.raw, strToBytes(plaintextStr));
}

TEST(CryptographyCipherFunctions, chacha20poly1305_encryptTest_correct)
{
	// the results are taken from the reference Rust implementation generated by noiseexplorer.com

	const std::string plaintextStr = "text to encrypt";

	Cryptography::CipherKey cipherKey;
	vectorToArray(hexToBytes("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f"), cipherKey.raw);

	Cryptography::Nonce nonce = 0xABCDEF0123456789;

	const Cryptography::DynByteSequence associatedData = Cryptography::DynByteSequence::fromVector(hexToBytes("000102030405060708090a0b0c0d0e0f"));

	const Cryptography::DynByteSequence plaintext = Cryptography::DynByteSequence::fromVector(strToBytes(plaintextStr));

	Cryptography::DynByteSequence ciphertext;
	ciphertext.clearResize(plaintext.size() + Cryptography::CipherAuthDataSize);
	ASSERT_EQ(Cryptography::encrypt_chacha20poly1305(cipherKey, nonce, associatedData, plaintext, ciphertext), Cryptography::EncryptResult::Success);

	std::vector<std::byte> expectedResult = hexToBytes("4b97a0b99cbe4e9316840e89792351e3572ee8c32d1fa534a1e3f9d0bd7093");

	EXPECT_EQ(expectedResult, ciphertext.raw);
}

