TEST(CryptographyCipherFunctions, chacha20poly1305_encryptTest_partiallyOverlappingBuffers)
{
	const std::string plaintextStr = "text to encrypt";

	Cryptography::CipherKey cipherKey;
	vectorToArray(hexToBytes("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f"), cipherKey.raw);

	Cryptography::Nonce nonce = 0xABCDEF0123456789;

	const Cryptography::DynByteSequence associatedData = Cryptography::DynByteSequence::fromVector(hexToBytes("000102030405060708090a0b0c0d0e0f"));

	std::vector<std::byte> plaintextVec = strToBytes(plaintextStr);
	plaintextVec.resize(plaintextVec.size() + Cryptography::CipherAuthDataSize + 2);
	// pad the plaintext with 1 byte from each side
	std::rotate(plaintextVec.begin(), plaintextVec.end(), plaintextVec.begin() + plaintextVec.size() - 1);
	Cryptography::DynByteSequence plaintext = Cryptography::DynByteSequence::fromVector(std::move(plaintextVec));

	ASSERT_EQ(Cryptography::encrypt_chacha20poly1305(cipherKey, nonce, associatedData, std::span<std::byte>(plaintext.raw.data() + 1, plaintext.size() - Cryptography::CipherAuthDataSize - 2), std::span<std::byte>(plaintext.raw.data(), plaintext.size() - 2)), Cryptography::EncryptResult::PartiallyOverlappingBuffers);
	ASSERT_EQ(Cryptography::encrypt_chacha20poly1305(cipherKey, nonce, associatedData, std::span<std::byte>(plaintext.raw.data() + 1, plaintext.size() - Cryptography::CipherAuthDataSize - 2), std::span<std::byte>(plaintext.raw.data() + 2, plaintext.size() - 2)), Cryptography::EncryptResult::PartiallyOverlappingBuffers);
	// sanity check
	ASSERT_EQ(Cryptography::encrypt_chacha20poly1305(cipherKey, nonce, associatedData, std::span<std::byte>(plaintext.raw.data() + 1, plaintext.size() - Cryptography::CipherAuthDataSize - 2), std::span<std::byte>(plaintext.raw.data() + 1, plaintext.size() - 2)), Cryptography::EncryptResult::Success);
}

TEST(CryptographyCipherFunctions, chacha20poly1305_decryptTest_correct)
{
	// the results are taken from the reference Rust implementation generated by noiseexplorer.com

	Cryptography::CipherKey cipherKey;
	vectorToArray(hexToBytes("101112131415161718191a1b1c1d1e1f000102030405060708090a0b0c0d0e0f"), cipherKey.raw);

	Cryptography::Nonce nonce = 0xABCDEF0123456789;

	Cryptography::DynByteSequence ciphertext = Cryptography::DynByteSequence::fromVector(hexToBytes("81a31e0ca246ecee4e8dc559ad8cf5193e1e04fc8b83b5702da4b9de13e2c5"));

	const Cryptography::DynByteSequence associatedData = Cryptography::DynByteSequence::fromVector(hexToBytes("08090a0b0c0d0e0f0001020304050607"));

	Cryptography::DynByteSequence plaintext;
	plaintext.clearResize(ciphertext.size() - Cryptography::CipherAuthDataSize);
	ASSERT_EQ(Cryptography::decrypt_chacha20poly1305(cipherKey, nonce, associatedData, ciphertext, plaintext), Cryptography::DecryptResult::Success);

	std::vector<std::byte> expectedResult = strToBytes("text to decrypt");
	EXPECT_EQ(expectedResult, plaintext.raw);
}

TEST(CryptographyCipherFunctions, chacha20poly1305_inPlaceDecryptTest_correct)
{
	Cryptography::CipherKey cipherKey;
	vectorToArray(hexToBytes("101112131415161718191a1b1c1d1e1f000102030405060708090a0b0c0d0e0f"), cipherKey.raw);

	Cryptography::Nonce nonce = 0xABCDEF0123456789;

	Cryptography::DynByteSequence ciphertext = Cryptography::DynByteSequence::fromVector(hexToBytes("81a31e0ca246ecee4e8dc559ad8cf5193e1e04fc8b83b5702da4b9de13e2c5"));

	std::vector<std::byte> expectedResult = strToBytes("text to decrypt");
	expectedResult.reserve(expectedResult.size() + Cryptography::CipherAuthDataSize);
	std::copy(ciphertext.raw.begin() + (ciphertext.size() - Cryptography::CipherAuthDataSize), ciphertext.raw.end(), std::back_inserter(expectedResult));

	const Cryptography::DynByteSequence associatedData = Cryptography::DynByteSequence::fromVector(hexToBytes("08090a0b0c0d0e0f0001020304050607"));

	ASSERT_EQ(Cryptography::decrypt_chacha20poly1305(cipherKey, nonce, associatedData, ciphertext, std::span<std::byte>(ciphertext.raw.data(), ciphertext.size() - Cryptography::CipherAuthDataSize)), Cryptography::DecryptResult::Success);

	EXPECT_EQ(expectedResult, ciphertext.raw);
}

